#include <vector>
#include <queue>
#include <algorithm>
#include <climits>

using namespace std;

struct Edge {
    int to;
    long long cost;
    Edge(int t, long long c) : to(t), cost(c) {}
};

long long solve(std::vector<std::vector<long long>> edges, std::vector<bool> online, long long k) {
    int n = online.size();
    vector<vector<Edge>> graph(n);
    for (const auto& e : edges) {
        int u = e[0], v = e[1];
        long long cost = e[2];
        graph[u].emplace_back(v, cost);
    }

    priority_queue<pair<long long, pair<long long, int>>> pq; // {min_cost, {total_cost, node}}
    pq.push({LLONG_MAX, {0, 0}});
    long long max_score = -1;

    while (!pq.empty()) {
        auto current = pq.top();
        pq.pop();
        long long current_min = current.first;
        long long current_cost = current.second.first;
        int u = current.second.second;

        if (u == n - 1) {
            if (current_cost <= k) {
                max_score = max(max_score, current_min);
            }
            continue;
        }

        for (const auto& edge : graph[u]) {
            int v = edge.to;
            long long cost = edge.cost;
            if (v != n - 1 && !online[v]) continue;

            long long new_total = current_cost + cost;
            if (new_total > k) continue;

            long long new_min = min(current_min, cost);
            pq.push({new_min, {new_total, v}});
        }
    }

    return max_score == LLONG_MAX ? -1 : max_score;
}

