import scala.collection.mutable

def solve(edges: Array[Array[Long]], online: Array[Boolean], k: Long): Long = {
    val n = online.length
    val graph = Array.fill(n)(mutable.ListBuffer[(Int, Long)]())
    for (e <- edges) {
        val u = e(0).toInt
        val v = e(1).toInt
        val cost = e(2)
        graph(u) += ((v, cost))
    }

    val pq = mutable.PriorityQueue[(Long, (Long, Int))]()(Ordering.by(_._1))
    pq.enqueue((Long.MaxValue, (0L, 0)))
    var maxScore = -1L

    while (pq.nonEmpty) {
        val current = pq.dequeue()
        val currentMin = current._1
        val currentCost = current._2._1
        val u = current._2._2

        if (u == n - 1) {
            if (currentCost <= k) {
                maxScore = math.max(maxScore, currentMin)
            }
        } else {
            for ((v, cost) <- graph(u)) {
                if (v != n - 1 && !online(v)) {
                    // Skip offline nodes except the destination
                } else {
                    val newTotal = currentCost + cost
                    if (newTotal <= k) {
                        val newMin = math.min(currentMin, cost)
                        pq.enqueue((newMin, (newTotal, v)))
                    }
                }
            }
        }
    }

    if (maxScore == Long.MaxValue) -1 else maxScore
}
